import Foundation

enum OperatorWebUI {
    static let html = #"""
    <!doctype html>
    <html lang="en">
    <head>
      <meta charset="utf-8">
      <meta name="viewport" content="width=device-width,initial-scale=1">
      <meta name="color-scheme" content="dark">
      <title>Noctweave Relay Console</title>
      <link rel="stylesheet" href="/admin/assets/app.css">
    </head>
    <body>
      <div class="ambient" aria-hidden="true"></div>
      <section class="login" id="login">
        <form class="loginCard" id="loginForm">
          <div class="brandMark">◇</div>
          <span class="eyebrow">Noctweave Relay</span>
          <h1>Operator Console</h1>
          <p>Manage this relay without exposing its control plane to messaging clients.</p>
          <label for="token">Admin token</label>
          <input id="token" type="password" autocomplete="current-password" required>
          <button class="primary" type="submit">Open Console</button>
          <p class="error" id="loginError" role="alert"></p>
        </form>
      </section>

      <main class="app" id="app" hidden>
        <aside class="rail">
          <div class="brand"><div class="brandMark small">◇</div><div><strong>Noctweave</strong><span>Relay Console</span></div></div>
          <nav id="navigation">
            <button type="button" data-view="overview" class="active"><span>◌</span> Overview</button>
            <button type="button" data-view="general"><span>◇</span> General</button>
            <button type="button" data-view="delivery"><span>⇄</span> Delivery</button>
            <button type="button" data-view="storage"><span>▣</span> Storage</button>
            <button type="button" data-view="federation"><span>⌁</span> Federation</button>
            <button type="button" data-view="advanced"><span>⚙</span> Privacy</button>
          </nav>
          <div class="railStatus"><span class="onlineDot"></span><span id="railStatus">Relay online</span></div>
        </aside>

        <section class="content">
          <header class="topbar">
            <div><span class="eyebrow" id="viewEyebrow">Operations</span><h2 id="viewTitle">Overview</h2></div>
            <div class="actions"><span class="statusPill"><span class="onlineDot"></span><span id="headerRelay">Connected</span></span><button type="button" id="logout" class="quiet">Lock</button></div>
          </header>

          <section class="view active" data-view-panel="overview">
            <div class="heroCard"><div><span class="eyebrow">Current relay</span><h3 id="overviewName">Noctweave Relay</h3><p id="overviewEndpoint">Not advertised</p></div><div class="badgeStack"><span class="badge good">Running</span><span class="badge warningBadge" id="restartBadge" hidden>Restart required</span></div></div>
            <div class="metricGrid">
              <article><span>Uptime</span><strong id="uptime">—</strong></article>
              <article><span>Federation</span><strong id="overviewFederation">—</strong></article>
              <article><span>Storage</span><strong id="overviewStorage">—</strong></article>
              <article><span>Transport</span><strong id="overviewTransport">—</strong></article>
            </div>
            <div class="sectionCard"><div class="cardHeader"><div><span class="eyebrow">Runtime profile</span><h3>Active process configuration</h3><p class="cardDescription">What this container is using right now.</p></div><span class="badge">Read only</span></div><dl class="details" id="bootstrapDetails"></dl><p class="hint">Listeners, database mode, request ceilings, and secrets remain container-controlled. Staged IPFS changes activate after restart.</p></div>
          </section>

          <form id="configForm">
            <section class="view" data-view-panel="general">
              <div class="sectionIntro"><div><span class="eyebrow">Public profile</span><h3>How clients see this relay</h3></div><p>Keep presentation concise and advertise the address clients actually reach.</p></div>
              <div class="sectionCard"><div class="cardHeader"><div><span class="eyebrow">Presentation</span><h3>Relay identity</h3><p class="cardDescription">Published through relay information responses.</p></div></div><div class="fieldGrid"><label>Relay name<input name="relayName" maxlength="1024" placeholder="Community Relay"></label><label>Advertised endpoint<input name="advertisedEndpoint" maxlength="2048" placeholder="https://relay.example.org"></label></div><label>Operator message<textarea name="operatorNote" maxlength="1024" rows="4" placeholder="Optional information shown to clients"></textarea></label><div class="callout"><strong>Public endpoint</strong><span>Use the client-facing HTTPS, WSS, TLS, or TCP address. Behind a reverse proxy, enter its public URL—not the container address.</span></div></div>
            </section>

            <section class="view" data-view-panel="delivery">
              <div class="sectionIntro"><div><span class="eyebrow">Traffic policy</span><h3>Delivery and retention</h3></div><p>Control observable timing and the payload capabilities offered to clients.</p></div>
              <div class="sectionCard"><div class="cardHeader"><div><span class="eyebrow">Timing</span><h3>Temporal bucketing</h3><p class="cardDescription">Coarsens relay-visible timestamps.</p></div></div><div class="fieldGrid"><label>Primary bucket (seconds)<input name="temporalBucketSeconds" type="number" min="0" max="86400"></label><label>Multi-bucket schedule<input name="temporalBucketScheduleSeconds" placeholder="60, 120, 300"></label></div><p class="hint">Use 0 with an empty schedule to disable bucketing. A schedule deterministically selects a bucket per routing identifier.</p></div>
              <div class="sectionCard"><div class="cardHeader"><div><span class="eyebrow">Payloads</span><h3>Attachments and groups</h3><p class="cardDescription">Availability, retention, and group protocol policy.</p></div><label class="switch"><input name="attachmentsEnabled" type="checkbox"><span></span>Attachments</label></div><div class="fieldGrid"><label>Default retention (seconds)<input name="attachmentDefaultTTLSeconds" type="number" min="60" max="21600"></label><label>Maximum retention (seconds)<input name="attachmentMaxTTLSeconds" type="number" min="60" max="21600"></label><label>Group creation<select name="groupCreationMode"><option value="allowed">Allowed</option><option value="disabled">Disabled</option></select></label><label>Group security<select name="groupSecurityModel"><option value="mlsDerivedTree">MLS-derived tree</option><option value="relayBackedPairwise">Relay-backed pairwise</option></select></label></div></div>
            </section>

            <section class="view" data-view-panel="storage">
              <div class="sectionIntro"><div><span class="eyebrow">Data plane</span><h3>Storage backends</h3></div><p>Choose where encrypted attachment chunks live without changing message confidentiality.</p></div>
              <div class="sectionCard"><div class="cardHeader"><div><span class="eyebrow">Encrypted blobs</span><h3>Attachment storage</h3><p class="cardDescription">Active backend: <strong id="activeAttachmentBackend">—</strong></p></div><span class="badge">Restart-controlled</span></div><div class="fieldGrid"><label>Desired backend<select name="attachmentStorageMode"><option value="inline">Inline relay storage</option><option value="ipfs">IPFS offload</option></select></label><label>IPFS timeout (seconds)<input name="ipfsTimeoutSeconds" type="number" min="1" max="300"></label></div><div class="ipfsOnly"><label>IPFS API endpoint<input name="ipfsAPIEndpoint" placeholder="http://ipfs:5001"></label><label>Optional gateway endpoint<input name="ipfsGatewayEndpoint" placeholder="http://ipfs:8080"></label></div><div class="callout warning"><strong>Encrypted chunks only</strong><span>IPFS receives ciphertext, never plaintext. Backend changes are staged until restart. Unpinning cannot guarantee deletion from third-party IPFS peers.</span></div></div>
              <div class="sectionCard compactCard"><div class="cardHeader"><div><span class="eyebrow">Persistent state</span><h3>Relay database</h3><p class="cardDescription">Queues, prekeys, routing metadata, and attachment records.</p></div><span class="badge">Docker-managed</span></div><p class="hint">SQLite lives in <code>/data</code>. RAM-only operation must be selected when starting the container and cannot be switched while requests are active.</p></div>
            </section>

            <section class="view" data-view-panel="federation">
              <div class="sectionIntro"><div><span class="eyebrow">Network topology</span><h3>Federation</h3></div><p>Define the relay trust domain, peers, discovery bounds, and coordinator policy.</p></div>
              <div class="sectionCard"><div class="cardHeader"><div><span class="eyebrow">Routing domain</span><h3>Federation mode</h3><p class="cardDescription">Modes are explicit trust boundaries and never mix silently.</p></div><span class="badge" id="federationBadge">Solo</span></div><div class="fieldGrid three"><label>Mode<select name="federationMode"><option value="solo">Solo</option><option value="manual">Manual</option><option value="curated">Curated</option><option value="open">Open</option></select></label><label>Federation name<input name="federationName" maxlength="1024"></label><label>Peer exchange limit<input name="relayPeerExchangeLimit" type="number" min="0" max="128"></label></div><label>Description<textarea name="federationDescription" maxlength="1024" rows="3"></textarea></label><div class="callout warning"><strong>Trust domains remain separate</strong><span>DHT and peer exchange are available only in open federation mode.</span></div></div>
              <div class="sectionCard"><div class="cardHeader"><div><span class="eyebrow">Peers</span><h3>Relay endpoints</h3><p class="cardDescription">One explicit endpoint per line.</p></div></div><label>Allowed or manually federated relays<textarea name="federationAllowList" rows="5" placeholder="https://relay-a.example.org&#10;wss://relay-b.example.org"></textarea></label><label>Coordinator endpoints<textarea name="federationCoordinatorEndpoints" rows="4" placeholder="https://coordinator.example.org"></textarea></label><label class="switch"><input name="allowPrivateFederationEndpoints" type="checkbox"><span></span>Allow private/LAN federation endpoints</label></div>
              <div class="sectionCard openOnly"><div class="cardHeader"><div><span class="eyebrow">Open federation</span><h3>DHT and peer discovery</h3></div><label class="switch"><input name="openFederationDHTEnabled" type="checkbox"><span></span>DHT node</label></div><div class="fieldGrid three"><label>Maximum records<input name="openFederationDHTMaxRecords" type="number" min="1" max="256"></label><label>Records per host<input name="openFederationDHTMaxRecordsPerHost" type="number" min="1" max="16"></label><label>Query record limit<input name="openFederationDHTMaxQueryRecords" type="number" min="1" max="512"></label></div></div>
              <div class="sectionCard"><div class="cardHeader"><div><span class="eyebrow">Coordinator policy</span><h3>Directory timing and curation</h3></div></div><div class="fieldGrid three"><label>Heartbeat (seconds)<input name="coordinatorHeartbeatSeconds" type="number" min="15" max="3600"></label><label>Max directory staleness<input name="coordinatorDirectoryMaxStalenessSeconds" type="number" min="30" max="86400"></label><label>Coordinator quorum<input name="curatedCoordinatorQuorum" type="number" min="1" max="16"></label></div><div class="switchRow"><label class="switch"><input name="curatedStrictPolicyEnabled" type="checkbox"><span></span>Strict curated policy</label><label class="switch"><input name="curatedRequireSignedDirectory" type="checkbox"><span></span>Require signed directory</label></div></div>
            </section>

            <section class="view" data-view-panel="advanced">
              <div class="sectionIntro"><div><span class="eyebrow">Optional capabilities</span><h3>Privacy and wake policy</h3></div><p>Advertise only mechanisms that this relay and its surrounding topology can actually provide.</p></div>
              <div class="sectionCard"><div class="cardHeader"><div><span class="eyebrow">Metadata reduction</span><h3>Hidden retrieval</h3></div><label class="switch"><input name="hiddenRetrievalEnabled" type="checkbox"><span></span>Advertise</label></div><div class="fieldGrid three"><label>Mode<select name="hiddenRetrievalMode"><option value="coverQuery">Cover query</option><option value="replicatedXorPIR">Replicated XOR-PIR</option></select></label><label>Default cover set<input name="hiddenRetrievalCoverSize" type="number" min="2" max="4096"></label><label>Maximum cover set<input name="hiddenRetrievalMaxCoverSize" type="number" min="2" max="4096"></label></div><label>Replicas (ID, operator ID, HTTPS/WSS endpoint)<textarea name="hiddenRetrievalReplicas" rows="4" placeholder="replica-a,operator-a,https://pir-a.example.org"></textarea></label></div>
              <div class="sectionCard"><div class="cardHeader"><div><span class="eyebrow">Route privacy</span><h3>Onion and mixnet capabilities</h3></div></div><div class="splitCards"><div><label class="switch"><input name="onionTransportEnabled" type="checkbox"><span></span>Onion transport</label><label>Maximum hops<input name="onionTransportMaxHops" type="number" min="2" max="8"></label><label class="switch"><input name="onionTransportRequiresFixedSizePackets" type="checkbox"><span></span>Require fixed-size packets</label></div><div><label class="switch"><input name="mixnetTransportEnabled" type="checkbox"><span></span>Mixnet scheduling</label><label>Batch interval (seconds)<input name="mixnetBatchIntervalSeconds" type="number" min="10" max="3600"></label><label>Minimum batch size<input name="mixnetMinBatchSize" type="number" min="4" max="256"></label><label>Cover packets per batch<input name="mixnetCoverPacketsPerBatch" type="number" min="1" max="256"></label><label>Maximum delay (seconds)<input name="mixnetMaxDelaySeconds" type="number" min="1" max="3600"></label></div></div><p class="hint">These fields advertise supported protocol behavior. Mixnet mode requires enabled onion routing, fixed-size packets, cover traffic, batching, and release delay.</p></div>
              <div class="sectionCard"><div class="cardHeader"><div><span class="eyebrow">Client wake policy</span><h3>Polling advertisement</h3></div></div><div class="fieldGrid three"><label>Mode<select name="wakeMode"><option value="disabled">Not advertised</option><option value="pullOnly">Pull only</option><option value="longPoll">Long poll</option></select></label><label>Minimum poll (seconds)<input name="wakeMinPollSeconds" type="number" min="5" max="86400"></label><label>Maximum poll (seconds)<input name="wakeMaxPollSeconds" type="number" min="5" max="86400"></label><label>Jitter (permille)<input name="wakeJitterPermille" type="number" min="0" max="1000"></label><label>Long-poll timeout<input name="wakeLongPollTimeoutSeconds" type="number" min="5" max="300"></label></div><div class="callout"><strong>Secrets stay outside the browser</strong><span>Relay passwords, admin tokens, coordinator registration tokens, and forwarding tokens remain environment or command-line settings and are never returned by this API.</span></div></div>
            </section>
          </form>

          <footer class="saveBar" id="saveBar" hidden><div><strong>Unsaved changes</strong><span id="saveMessage">Policy changes apply to new requests immediately.</span></div><button type="button" id="discard" class="quiet">Discard</button><button type="button" id="save" class="primary">Save configuration</button></footer>
        </section>
      </main>
      <div class="toast" id="toast" role="status" aria-live="polite" hidden></div>
      <script src="/admin/assets/app.js" defer></script>
    </body>
    </html>
    """#

    static let css = #"""
    :root{color-scheme:dark;font-family:Inter,ui-sans-serif,system-ui,-apple-system,BlinkMacSystemFont,"Segoe UI",sans-serif;--bg:#07090d;--surface:rgba(29,32,40,.82);--line:rgba(255,255,255,.105);--text:#f7f7fa;--muted:#9fa4b2;--accent:#8274ff;--accent2:#4ad5c2;--danger:#ff7382;--shadow:0 30px 100px rgba(0,0,0,.38)}
    *{box-sizing:border-box}[hidden]{display:none!important}body{margin:0;min-height:100vh;background:var(--bg);color:var(--text)}.ambient{position:fixed;inset:0;pointer-events:none;background:radial-gradient(circle at 14% 8%,rgba(98,79,226,.23),transparent 38rem),radial-gradient(circle at 92% 72%,rgba(26,172,166,.15),transparent 36rem),linear-gradient(145deg,#07090d,#111723 58%,#071519)}button,input,textarea,select{font:inherit}button{border:1px solid rgba(151,139,255,.38);border-radius:14px;background:rgba(125,109,255,.16);color:var(--text);padding:10px 15px;cursor:pointer;transition:160ms ease}button:hover{transform:translateY(-1px);background:rgba(125,109,255,.27);border-color:rgba(171,161,255,.62)}button:disabled{opacity:.4;cursor:not-allowed}.primary{background:linear-gradient(135deg,#7867ed,#6759d1);box-shadow:0 10px 32px rgba(91,73,211,.22)}.quiet{background:rgba(255,255,255,.04);border-color:var(--line)}input,textarea,select{width:100%;border:1px solid var(--line);border-radius:14px;background:rgba(5,7,12,.62);color:var(--text);padding:12px 13px;outline:none;margin-top:7px}textarea{resize:vertical;line-height:1.5}input:focus,textarea:focus,select:focus{border-color:rgba(151,139,255,.76);box-shadow:0 0 0 3px rgba(125,109,255,.14)}label,.eyebrow{color:var(--muted);font-size:.73rem;font-weight:750;letter-spacing:.09em;text-transform:uppercase}.login{position:relative;z-index:3;min-height:100vh;display:grid;place-items:center;padding:24px}.loginCard{width:min(440px,100%);border:1px solid var(--line);border-radius:28px;background:rgba(22,25,33,.91);backdrop-filter:blur(34px);box-shadow:var(--shadow);padding:34px}.loginCard h1{margin:12px 0 8px;font-size:2rem}.loginCard p{color:var(--muted);line-height:1.55}.loginCard .primary{width:100%;margin-top:16px}.error{min-height:1.3em;color:#ff9da8!important}.brandMark{display:grid;place-items:center;width:58px;height:58px;border:1px solid rgba(151,139,255,.43);border-radius:18px;background:linear-gradient(145deg,rgba(125,109,255,.26),rgba(74,213,194,.1));font-size:2rem;color:#d8d2ff}.brandMark.small{width:42px;height:42px;border-radius:14px;font-size:1.4rem}.app{position:relative;z-index:1;min-height:100vh;display:grid;grid-template-columns:230px minmax(0,1fr)}.rail{position:sticky;top:0;height:100vh;border-right:1px solid var(--line);background:rgba(13,16,22,.68);backdrop-filter:blur(28px);padding:25px 18px;display:flex;flex-direction:column}.brand{display:flex;align-items:center;gap:11px;padding:0 7px 24px}.brand strong,.brand span{display:block}.brand span{color:var(--muted);font-size:.76rem;margin-top:2px}.rail nav{display:grid;gap:6px}.rail nav button{display:flex;align-items:center;gap:11px;border-color:transparent;background:transparent;text-align:left;color:#aeb3c0}.rail nav button span{width:20px;text-align:center}.rail nav button.active{color:#fff;background:rgba(125,109,255,.19);border-color:rgba(151,139,255,.2)}.railStatus{margin-top:auto;display:flex;align-items:center;gap:8px;padding:12px;color:var(--muted);font-size:.78rem}.onlineDot{width:8px;height:8px;border-radius:50%;background:var(--accent2);box-shadow:0 0 14px rgba(74,213,194,.65)}.content{min-width:0;padding:28px clamp(20px,4vw,52px) 110px}.topbar{display:flex;align-items:center;justify-content:space-between;gap:20px;max-width:1120px;margin:0 auto 24px}.topbar h2{font-size:1.75rem;margin:4px 0 0}.actions{display:flex;align-items:center;gap:9px}.statusPill,.badge{display:inline-flex;align-items:center;gap:8px;border:1px solid var(--line);border-radius:999px;background:rgba(255,255,255,.055);padding:9px 13px;font-size:.82rem}.badge.good{color:#87e9da;background:rgba(74,213,194,.08);border-color:rgba(74,213,194,.2)}.view{display:none;max-width:1120px;margin:0 auto}.view.active{display:grid;gap:14px;animation:enter .2s ease}.sectionCard,.heroCard,.metricGrid article{border:1px solid var(--line);background:var(--surface);backdrop-filter:blur(24px);box-shadow:var(--shadow);border-radius:22px}.sectionCard{padding:22px}.heroCard{padding:24px;display:flex;align-items:center;justify-content:space-between}.heroCard h3,.cardHeader h3{margin:4px 0 0;font-size:1.25rem}.heroCard p{color:var(--muted);margin:7px 0 0}.metricGrid{display:grid;grid-template-columns:repeat(4,1fr);gap:12px}.metricGrid article{padding:18px}.metricGrid span,.metricGrid strong{display:block}.metricGrid span{color:var(--muted);font-size:.78rem}.metricGrid strong{margin-top:8px}.cardHeader{display:flex;align-items:center;justify-content:space-between;gap:16px;margin-bottom:18px}.fieldGrid{display:grid;grid-template-columns:repeat(2,1fr);gap:14px;margin-bottom:16px}.fieldGrid.three{grid-template-columns:repeat(3,1fr)}.callout{border:1px solid var(--line);border-radius:16px;background:rgba(255,255,255,.035);padding:15px;margin-top:16px}.callout strong,.callout span{display:block}.callout span,.hint{margin-top:5px;color:var(--muted);font-size:.83rem;line-height:1.5}.callout.warning{border-color:rgba(255,190,92,.2);background:rgba(255,190,92,.04)}.details{display:grid;grid-template-columns:180px minmax(0,1fr);gap:10px;margin:18px 0}.details dt{color:var(--muted)}.details dd{margin:0;overflow-wrap:anywhere}.switch{display:flex;align-items:center;gap:9px;text-transform:none;letter-spacing:0}.switch input{width:auto;margin:0}.switch span{width:34px;height:20px;border-radius:999px;background:#3b4050;position:relative}.switch span:after{content:"";position:absolute;width:14px;height:14px;left:3px;top:3px;border-radius:50%;background:#fff;transition:.16s}.switch input{position:absolute;opacity:0}.switch input:checked+span{background:#6f61df}.switch input:checked+span:after{transform:translateX(14px)}.saveBar{position:fixed;z-index:5;left:260px;right:30px;bottom:22px;max-width:1060px;margin:auto;border:1px solid rgba(151,139,255,.28);border-radius:19px;background:rgba(24,27,35,.94);backdrop-filter:blur(26px);box-shadow:var(--shadow);padding:13px 15px;display:flex;align-items:center;gap:10px}.saveBar div{margin-right:auto}.saveBar strong,.saveBar span{display:block}.saveBar span{color:var(--muted);font-size:.78rem;margin-top:3px}.toast{position:fixed;z-index:20;right:24px;bottom:24px;border:1px solid var(--line);border-radius:14px;background:rgba(27,31,40,.96);box-shadow:var(--shadow);padding:13px 16px}.toast.error{color:#ffacb5}@keyframes enter{from{opacity:0;transform:translateY(7px)}to{opacity:1;transform:none}}
    .badgeStack{display:flex;align-items:flex-end;gap:8px;flex-direction:column}.warningBadge{color:#ffd191;border-color:rgba(255,190,92,.25);background:rgba(255,190,92,.08)}code{color:#c8c1ff;background:rgba(125,109,255,.1);border-radius:6px;padding:2px 6px}.ipfsOnly{display:grid;grid-template-columns:1fr 1fr;gap:14px;margin-bottom:16px}.switchRow{display:flex;gap:24px;flex-wrap:wrap}.splitCards{display:grid;grid-template-columns:1fr 1fr;gap:16px}.splitCards>div{display:grid;align-content:start;gap:15px;border:1px solid var(--line);border-radius:17px;background:rgba(255,255,255,.025);padding:18px}.disabled{opacity:.42;pointer-events:none;filter:saturate(.7)}
    .sectionIntro{display:flex;align-items:flex-end;justify-content:space-between;gap:28px;padding:2px 3px 7px}.sectionIntro h3{font-size:1.38rem;margin:5px 0 0}.sectionIntro p{max-width:520px;margin:0;color:var(--muted);font-size:.88rem;line-height:1.55;text-align:right}.cardDescription{margin:6px 0 0;color:var(--muted);font-size:.82rem;font-weight:500;line-height:1.45}.cardDescription strong{color:#d8dbe3}.compactCard .cardHeader{margin-bottom:8px}.sectionCard>label{display:block;margin-top:16px}.sectionCard>label:first-child{margin-top:0}.fieldGrid label,.ipfsOnly label,.splitCards label{display:block}.fieldGrid{align-items:start}.switchRow .switch{margin-top:2px}.topbar{position:sticky;z-index:4;top:0;padding:15px 0 17px;background:linear-gradient(180deg,rgba(10,13,19,.96) 0%,rgba(10,13,19,.82) 70%,transparent 100%);backdrop-filter:blur(18px)}button:focus-visible,input:focus-visible,textarea:focus-visible,select:focus-visible{outline:2px solid rgba(180,171,255,.92);outline-offset:2px}.rail nav button:focus-visible{outline-offset:-1px}.saveBar button{white-space:nowrap}.toast{max-width:min(420px,calc(100vw - 32px));line-height:1.4}
    @media(max-width:820px){.app{grid-template-columns:1fr;padding-bottom:82px}.rail{position:fixed;z-index:10;inset:auto 10px 10px;height:auto;border:1px solid var(--line);border-radius:20px;padding:7px;background:rgba(24,28,36,.94)}.brand,.railStatus{display:none}.rail nav{display:flex;gap:3px;overflow-x:auto;scrollbar-width:none}.rail nav::-webkit-scrollbar{display:none}.rail nav button{flex:1 0 72px;display:grid;justify-items:center;gap:2px;padding:8px 4px;font-size:.6rem}.content{padding:0 14px 118px}.topbar{align-items:flex-start;padding:18px 2px 15px}.statusPill{display:none}.metricGrid,.fieldGrid,.fieldGrid.three,.ipfsOnly,.splitCards{grid-template-columns:1fr}.metricGrid{grid-template-columns:repeat(2,1fr)}.sectionIntro{display:block;padding:2px 3px 4px}.sectionIntro p{text-align:left;margin-top:8px}.sectionCard{padding:18px;border-radius:19px}.cardHeader{align-items:flex-start}.saveBar{left:14px;right:14px;bottom:82px;padding:10px}.saveBar div{display:none}.details{grid-template-columns:1fr;gap:4px}.details dd{margin-bottom:8px}.heroCard{align-items:flex-start}.badgeStack{align-items:flex-end}}
    @media(prefers-reduced-motion:reduce){*,*:before,*:after{scroll-behavior:auto!important;animation-duration:.001ms!important;transition-duration:.001ms!important}}
    """#

    static let javascript = #"""
    const $=s=>document.querySelector(s), $$=s=>[...document.querySelectorAll(s)];
